2. # define:
    - # FIBO:
        - # initial values:
            - # F0 = 0, F1 = 1
        - # recurrence relation:
            - # Fn = Fn-1 + Fn-2 for n >= 2
4. # calculate:
    - # sum:
        - # initialize sum to 0
        - # iterate over terms:
            - # for each n starting from 1:
                - # calculate numerator: Fn+1 = Fn + Fn-1
                - # calculate denominator: Fn*Fn+2 = Fn*(Fn+1 + Fn) = Fn*(Fn + Fn + Fn-1) = Fn*2*Fn + Fn*Fn-1
                - # add term to sum: sum += numerator / denominator
5. # return:
    - # the computed sum as a float

